           setError(data["errors"].map((error: any) => error["message"]).join(", "));
        } else {
           setError("Oops! There was a problem submitting your form");
        }
      }
    } catch (err) {
      setError("Network error. Please try again.");
    } finally {
      setIsSubmitting(false);
