          <label htmlFor="name" className="block text-sm font-semibold text-gray-700 mb-1">Full Name</label>
          <input
            type="text"
            id="name"
            name="name"
            required
            placeholder="e.g. Rahul Sharma"
            value={formData.name}
            onChange={handleChange}
            className="w-full px-4 py-3 rounded-lg border border-gray-300 focus:ring-2 focus:ring-green-500 focus:border-transparent transition outline-none"
          />
        </div>

        <div>
          <label htmlFor="mobile" className="block text-sm font-semibold text-gray-700 mb-1">Mobile Number</label>
          <input
            type="tel"
            id="mobile"
            name="mobile"
            required
            placeholder="e.g. 98765 43210"
            value={formData.mobile}
            onChange={handleChange}
            className="w-full px-4 py-3 rounded-lg border border-gray-300 focus:ring-2 focus:ring-green-500 focus:border-transparent transition outline-none"
          />
        </div>

        <div>
          <label htmlFor="email" className="block text-sm font-semibold text-gray-700 mb-1">Email Address</label>
          <input
            type="email"
            id="email"
            name="email"
            required
            placeholder="e.g. rahul@example.com"
            value={formData.email}
            onChange={handleChange}
