import React, { useState } from 'react';
import { LeadFormProps } from '../types';
import { Loader2, ArrowRight, Lock } from 'lucide-react';

const LeadForm: React.FC<LeadFormProps> = ({ onSuccess }) => {
  const [formData, setFormData] = useState({
    name: '',
    mobile: '',
    email: ''
  });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [errors, setErrors] = useState<{name?: string, mobile?: string, email?: string, general?: string}>({});

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
    // Clear specific error on change
    if (errors[e.target.name as keyof typeof errors]) {
      setErrors({
        ...errors,
        [e.target.name]: undefined,
        general: undefined
      });
    }
  };

  const validateForm = () => {
    const newErrors: typeof errors = {};
    let isValid = true;

    // Name
    if (formData.name.trim().length < 2) {
      newErrors.name = "Please enter a valid full name.";
      isValid = false;
    }
    // Mobile
    const cleanPhone = formData.mobile.replace(/\D/g, '');
    if (cleanPhone.length < 10) {
      newErrors.mobile = "Please enter a valid mobile number (at least 10 digits).";
      isValid = false;
    }
    // Email
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(formData.email)) {
      newErrors.email = "Please enter a valid email address.";
      isValid = false;
    }

    setErrors(newErrors);
    return isValid;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setErrors({});

    if (!validateForm()) {
        return;
    }

    setIsSubmitting(true);

    try {
      const response = await fetch("https://formspree.io/f/xkgderno", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Accept": "application/json"
        },
        body: JSON.stringify(formData)
      });

      if (response.ok) {
        onSuccess();
      } else {
        const data = await response.json();
        if (Object.prototype.hasOwnProperty.call(data, 'errors')) {
           const generalErr = data["errors"].map((error: any) => error["message"]).join(", ");
           setErrors(prev => ({ ...prev, general: generalErr }));
        } else {
           setErrors(prev => ({ ...prev, general: "Oops! There was a problem submitting your form" }));
        }
      }
    } catch (err) {
      setErrors(prev => ({ ...prev, general: "Network error. Please try again." }));
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="bg-white rounded-xl shadow-2xl p-6 md:p-8 border border-gray-200">
      <div className="text-center mb-6">
        <h3 className="text-2xl font-bold text-gray-900 leading-tight">
          Get Free Access to the Insurance Agents’ Learning Community
        </h3>
        <p className="text-gray-600 mt-2 text-sm">Join 100,000+ serious professionals today.</p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-5" noValidate>
        <div className="relative">
          <label htmlFor="name" className="block text-sm font-semibold text-gray-700 mb-1">Full Name</label>
          <input
            type="text"
            id="name"
            name="name"
            required
            placeholder="e.g. Rahul Sharma"
            value={formData.name}
            onChange={handleChange}
            className={`w-full px-4 py-3 rounded-lg border bg-white text-gray-900 focus:ring-2 transition outline-none ${
                errors.name 
                ? 'border-red-500 focus:ring-red-500 focus:border-red-500' 
                : 'border-gray-300 focus:ring-green-500 focus:border-transparent'
            }`}
          />
          {errors.name && <p className="text-red-600 text-xs mt-1 font-medium">{errors.name}</p>}
        </div>

        <div className="relative">
          <label htmlFor="mobile" className="block text-sm font-semibold text-gray-700 mb-1">Mobile Number</label>
          <input
            type="tel"
            id="mobile"
            name="mobile"
            required
            placeholder="e.g. 98765 43210"
            value={formData.mobile}
            onChange={handleChange}
            className={`w-full px-4 py-3 rounded-lg border bg-white text-gray-900 focus:ring-2 transition outline-none ${
                errors.mobile
                ? 'border-red-500 focus:ring-red-500 focus:border-red-500' 
                : 'border-gray-300 focus:ring-green-500 focus:border-transparent'
            }`}
          />
          {errors.mobile && <p className="text-red-600 text-xs mt-1 font-medium">{errors.mobile}</p>}
        </div>

        <div className="relative">
          <label htmlFor="email" className="block text-sm font-semibold text-gray-700 mb-1">Email Address</label>
          <input
            type="email"
            id="email"
            name="email"
            required
            placeholder="e.g. rahul@example.com"
            value={formData.email}
            onChange={handleChange}
            className={`w-full px-4 py-3 rounded-lg border bg-white text-gray-900 focus:ring-2 transition outline-none ${
                errors.email
                ? 'border-red-500 focus:ring-red-500 focus:border-red-500' 
                : 'border-gray-300 focus:ring-green-500 focus:border-transparent'
            }`}
          />
          {errors.email && <p className="text-red-600 text-xs mt-1 font-medium">{errors.email}</p>}
        </div>

        {errors.general && (
          <div className="text-red-600 text-sm bg-red-50 p-3 rounded-lg border border-red-200 font-medium">
            {errors.general}
          </div>
        )}

        <button
          type="submit"
          disabled={isSubmitting}
          className="w-full bg-green-600 hover:bg-green-700 text-white font-bold py-4 rounded-lg text-lg shadow-lg hover:shadow-xl transform transition-all active:scale-95 flex items-center justify-center gap-2"
        >
          {isSubmitting ? (
            <Loader2 className="animate-spin" />
          ) : (
            <>
              Get Free Access <ArrowRight size={20} />
            </>
          )}
        </button>

        <div className="flex items-center justify-center gap-2 text-xs text-gray-500 mt-4">
          <Lock size={12} />
          <span>No spam • Serious agents only • You can exit anytime</span>
        </div>
      </form>
    </div>
  );
};

export default LeadForm;
